/**
 * Composes single-argument functions from right to left. The rightmost
 * function can take multiple arguments; the remaining functions must be unary.
 *
 * @example
 * const add = (n) => n + 1;
 * const multiply = (n) => n * 2;
 * const toString = (n) => `Result: ${n}`;
 *
 * const compute = compose(toString, multiply, add);
 * compute(5); // "Result: 12"
 *
 * @param {...Function} fns The functions to compose.
 * @returns {Function} A new function obtained by composing the input functions
 * from right to left.
 */
export function compose(): <R>(a: R) => R;

export function compose<F extends (...args: any[]) => any>(f: F): F;
export function compose<A, B, C>(f: (b: B) => C, g: (a: A) => B): (a: A) => C;
export function compose<A, B, C, D>(f: (c: C) => D, g: (b: B) => C, h: (a: A) => B): (a: A) => D;
export function compose<A, B, C, D, E>(
  f: (d: D) => E,
  g: (c: C) => D,
  h: (b: B) => C,
  i: (a: A) => B,
): (a: A) => E;

export function compose(...fns: readonly ((...args: any[]) => any)[]) {
  if (fns.length === 0) {
    return <T>(arg: T): T => arg;
  }

  if (fns.length === 1) {
    return fns[0];
  }

  return fns.reduce(
    (a, b) =>
      (...args: any[]) =>
        a(b(...args)),
  );
}

