  dispatch,
  subscribe,
  getState,
} as Instance<State>;
```

**Nota**: O `as Instance<State>` pode ser seguro se a implementacao estiver correta, mas e melhor usar satisfies ou type assertion functions.

---

### 4. list.ts - Otimizacao O(n^2) para O(n)

**ATENCAO: Mudanca comportamental sutil**

```typescript
// Antes (spread):
return items.reduce((acc, entry) => {
  const next = reducer(entry);
  return { ...acc, ...next };
}, {} as Result);

// Proposto:
const result = {} as Result;
for (const item of items) {
  const next = reducer(item);
  if (next) Object.assign(result, next);
}
return result;
```

**Problemas:**

1. **Spread vs Object.assign - Diferencas sutis**:
   - `Object.assign` modifica o primeiro argumento in-place
   - Spread `{ ...acc, ...next }` sempre cria novo objeto
   - Para este caso, isso e OK porque `result` e o objeto mutado

2. **Verificacao de `if (next)` esta INCORRETA**:
   - A funcao `reducer` pode retornar `Partial<Result> | undefined`
