export function reduce<Result extends object, const Item>(
  items: ReadonlyArray<Item>,
  reducer: (next: Item) => Partial<Result> | undefined,
): Result {
  const result = {} as Result;
  for (const item of items) {
    const next = reducer(item);
    if (next !== undefined) {
      Object.assign(result, next);
    }
  }
  return result;
}

import type {
  AnyRecord,
  AsString,
  Cast,
  Compute,
  Merge,
  Paths,
  PathType,
  Writable,
} from '../../helpers/type-utils';

import type {
  AnyAsyncSlice,
  CombineSlicesState,
  ExtractSelectorValues,
  MachineSelectors,
  MachineSlices,
  SliceToActionCreators,
} from './commons';

import type { SliceKind } from './slice';

/**
 * Defines the overloaded signature for the `useMachine` hook, allowing it to
 * select state from sync slices/selectors or interact with async slices.
 */

export type MachineHook<
  Slices extends MachineSlices,
  Selectors extends MachineSelectors<any>,
> = RootSelector<Slices, MergeAll<Slices, Selectors>, AsString<keyof Slices>>;

export type MachineUseSelector<State> = <T>(select: (state: State) => T) => T;

type MergeAll<Slices extends MachineSlices, Selectors extends MachineSelectors<any>> = Merge<
  Merge<CombineSlicesState<OnlyAsyncSlices<Slices>>, CombineSlicesState<OnlySyncSlices<Slices>>>,
  Compute<Writable<ExtractSelectorValues<Selectors>>>
>;

export type SliceRooks<Slice> = {
  [K in keyof SliceToActionCreators<Slice>]: SliceToActionCreators<Slice>[K] extends (
    ...args: infer Args
  ) => any
    ? (...args: Cast<Args, any[]>) => void
    : never;
};

/**
 * Selector return type. Returns { state, actions } for slices.
 */
type RootSelector<
  Slices extends MachineSlices,
  RootState extends AnyRecord,
  SliceKey extends keyof Slices,
> = <P extends Paths<RootState>>(
  path: P,
) => P extends SliceKey
  ? {
      state: Compute<RootState[P]>;
      actions: SliceRooks<Slices[P]>;
    }
  : PathType<RootState, P>;

type OnlyAsyncSlices<Slices extends MachineSlices> = {
  [K in keyof Slices as [Slices[K]['kind']] extends [SliceKind.async] ? K : never]: Cast<
    Slices[K],
    AnyAsyncSlice
  >;
};

type OnlySyncSlices<Slices extends MachineSlices> = {
  [K in keyof Slices as [Slices[K]['kind']] extends [SliceKind.sync] ? K : never]: Slices[K];
};

