import { devAssert, devLog } from '../helpers/logs';
import { ms } from '../helpers/ms';
import { objectKeys } from '../helpers/object-utils';
import type { AnyRecord } from '../helpers/type-utils';
import { createModel } from '../schema';
import {
  CachePolicy,
  type CacheStrategy,
  type CacheStrategyField,
  type MachineMetadata,
  type MachineSliceInfo,
  type MachineUserID,
  type SliceContext,
  type StringTypes,
} from './models';
import type { Slices } from './slice';

export namespace Cache {
  /**
   * @internal
   * @private
   */
  export type Invalidation = {
    sliceKey: StringTypes.SliceKey;
    reason: CacheStrategyField | `${CacheStrategyField}ConfigMismatch` | 'unknown';
    configValue: CacheStrategy[CacheStrategyField] | null;
    cachedComparedValue: string | number | null | undefined;
    currentComparedValue: string | number | null | undefined;
    details?: string;
  };

  export function IsStaleByTTL(
    cacheStrategy: CacheStrategy,
    cachedMetadata: MachineMetadata,
  ): boolean {
    const { ttl: ttlConfig } = cacheStrategy;
    const { updatedAt: cachedUpdatedAt } = cachedMetadata;

    if (ttlConfig !== undefined) {
      const ttlMS = ms(ttlConfig);
      const elapsed = Date.now() - cachedUpdatedAt;
      if (ttlMS === 0 || (ttlMS > 0 && elapsed > ttlMS)) {
        return true;
      }
    }
    return false;
  }

  /**
   * @internal
   * @private
   */
  export type SliceInvalidation = {
    sliceKey: StringTypes.SliceKey;
    invalidations: Invalidation[];
    invalidatedBy: Invalidation['reason'][];
  };

  export function GetInvalidations(params: {
    mappedSlice: MachineSliceInfo;
    cachedMetadata: MachineMetadata;
    currentUserID: MachineUserID;
    currentSessionID: string;
  }): SliceInvalidation | null {
    const {
      //
      currentSessionID,
      mappedSlice,
      currentUserID,
      cachedMetadata,
    } = params;

    const { sliceKey, slice } = mappedSlice;

    const {
      updatedAt: cachedUpdatedAt,
      userID: cacheUserID,
      sessionID: cacheSessionID,
      slicesCacheStrategy: cachedSlicesCacheStrategy,
    } = cachedMetadata;

    const oldSliceStrategy = cachedSlicesCacheStrategy?.[sliceKey];

    const currentSliceStrategy = slice.cache;

    const invalidations: SliceInvalidation = {
      sliceKey,
      invalidatedBy: [],
      invalidations: [],
    };

    const push = (item: Invalidation) => {
      invalidations.invalidations.push(item);
      invalidations.invalidatedBy.push(item.reason);
    };

    if (oldSliceStrategy) {
      const allKeys = new Set([
        ...Object.keys(oldSliceStrategy),
        ...Object.keys(currentSliceStrategy),
      ]) as Set<keyof CacheStrategy>;

      for (const key of allKeys) {
        if (key !== 'swr' && oldSliceStrategy[key] !== currentSliceStrategy[key]) {
          push({
            sliceKey,
            reason: `${key}ConfigMismatch`,
            configValue: currentSliceStrategy[key] as never,
            currentComparedValue: null,
            cachedComparedValue: null,
          });
        }
      }
    } else {
      push({
        sliceKey,
        reason: 'unknown',
        configValue: null,
        currentComparedValue: null,
        cachedComparedValue: null,
        details: `cachedSlicesCacheStrategy?.["${sliceKey}"] is undefined.`,
      });
    }

    if (currentSliceStrategy.ttl !== undefined) {
      if (IsStaleByTTL(currentSliceStrategy, cachedMetadata)) {
        push({
          sliceKey,
          reason: 'ttl',
          configValue: currentSliceStrategy.ttl,
          currentComparedValue: Date.now(),
          cachedComparedValue: cachedUpdatedAt,
        });
      }
    }

    const { policy } = currentSliceStrategy;

    switch (policy) {
      case 'public': {
        break; // already validated by ttl, above.
      }

      case 'session': {
        if (cacheSessionID !== currentSessionID) {
          push({
            sliceKey,
            reason: 'policy',
            configValue: policy,
            currentComparedValue: currentSessionID,
            cachedComparedValue: cacheSessionID,
          });
        }
        break;
      }

      case 'private': {
        if (currentUserID !== cacheUserID) {
          push({
            sliceKey,
            reason: 'policy',
            configValue: policy,
            currentComparedValue: currentUserID,
            cachedComparedValue: cacheUserID,
          });
        }
        break;
      }

      default: {
        const message = `GetCacheInvalidations found invalid policy: ${policy}`;
        devAssert(new Error(message));
        break;
      }
    }

    return invalidations.invalidations.length ? invalidations : null;
  }

  export type StateInvalidationsReport<T = AnyRecord> = {
    cleanState: T;
    stale: StringTypes.SliceKey[];
    reset: StringTypes.SliceKey[];
    invalidations: SliceInvalidation[];
  };

  export function StateInvalidations<T extends AnyRecord>(params: {
    mappedSlices: Slices.SlicesMap;
    getContext: () => SliceContext;
    cachedState: T;
    currentSessionID: string;
    cachedMetadata: MachineMetadata;
  }): StateInvalidationsReport<T> {
    const { getContext, mappedSlices, currentSessionID, cachedState, cachedMetadata } = params;

    const result: StateInvalidationsReport<T> = {
      reset: [],
      stale: [],
      cleanState: { ...cachedState },
      invalidations: [],
    };

    mappedSlices.info.forEach((mappedSlice) => {
      const { sliceKey, slice } = mappedSlice;

      if (!(sliceKey in cachedState)) return;

      const cacheInvalidations = GetInvalidations({
        currentSessionID,
        mappedSlice,
        currentUserID: getContext().userID,
        cachedMetadata,
      });

      if (cacheInvalidations) {
        devLog(`Cache invalidations for ${sliceKey}: `, cacheInvalidations);

        result.invalidations.push(cacheInvalidations);
        const swr = slice.cache.swr === true;
        const isStale =
          swr &&
          cacheInvalidations.invalidatedBy.length === 1 &&
          cacheInvalidations.invalidatedBy[0] === 'ttl';

        if (isStale) {
          result.stale.push(sliceKey);
        } else {
          Object.assign(result.cleanState, {
            [sliceKey]: mappedSlices.mergedSlicesInitialState[sliceKey],
          });
        }
      }
    });

    return result;
  }

  export const Model = createModel({
    policy: { enum: objectKeys(CachePolicy) },
    ttl: 'string?',
    swr: 'boolean?',
  });
}

