    return Type.String();
  }

  if (type === 'number') {
    return Type.Number();
  }

  if (type === 'boolean') {
    return Type.Boolean();
  }

  if (type === 'date') {
    return createDateType();
  }

  if (type === 'null') {
    return Type.Null();
  }

  if (type === 'undefined') {
    return Type.Undefined();
