      const recordValue = toTypeBox(type.record as TypeDefinition);
      return Type.Record(Type.String(), recordValue);
    }
  }

  throw new InvariantError(`Invalid type definition`, createType, type);
}

function _createType<const Definition extends TypeDefinition>(
  definition: Definition,
